<?php
/**
 * SpinWheel Pro — Full Fix Patch
 * Generated: 20260327_104405
 * ══════════════════════════════════════════════════════
 * Fixes 7 files — all syntax errors + DB column mismatches
 *
 * Root causes of 500 on dashboard:
 *   participants table has: result_name, spun_at, ip_address
 *   Code was using:         prize_won,  created_at, name, email, phone
 *   → All SQL queries updated to use correct column names
 *   → name/email pulled via subquery from participant_answers
 *
 * Files fixed:
 *   admin/dashboard.php    — wrong participants column names
 *   admin/participants.php — wrong participants column names + search
 *   admin/export.php       — wrong participants column names
 *   admin/users.php        — PHP syntax error (curly quote)
 *   admin/organisation.php — PHP syntax error (curly quote)
 *   admin/projects.php     — PHP syntax error (curly quote)
 *   admin/migrate_rbac.php — PHP syntax error (function scope)
 *
 * Safe: config.php, DB data, all other files untouched.
 * ══════════════════════════════════════════════════════
 */
set_time_limit(120);
$ROOT = __DIR__;
$OK = []; $ERRORS = [];
$RUN = isset($_POST['fix']) && $_POST['fix'] === 'yes';

$scheme = (!empty($_SERVER['HTTPS']) && $_SERVER['HTTPS'] !== 'off') ? 'https' : 'http';
$host   = $_SERVER['HTTP_HOST'] ?? 'localhost';
$doc    = rtrim(str_replace("\\", "/", (string)realpath($_SERVER['DOCUMENT_ROOT'] ?? '')), '/');
$app    = rtrim(str_replace("\\", "/", (string)realpath(__DIR__)), '/');
$sub    = ($doc && strlen($doc) && strpos($app, $doc) === 0) ? substr($app, strlen($doc)) : '';
$URL    = rtrim($scheme . '://' . $host . $sub, '/');

if ($RUN) {
    $raw     = base64_decode('');
    $payload = json_decode($raw, true);
    if (!$payload) {
        $ERRORS[] = 'Payload decode failed — re-upload the file.';
    } else {
        foreach ($payload as $rel => $b64) {
            $full    = $ROOT . '/' . $rel;
            $content = base64_decode($b64);
            if (file_put_contents($full, $content) !== false) {
                $OK[] = [$rel, strlen($content)];
            } else {
                $ERRORS[] = "Cannot write: $rel (check permissions)";
            }
        }
    }
}
$allOk = $RUN && empty($ERRORS) && !empty($OK);
?>
